import React,{useState} from "react";
import { Link, useNavigate } from "react-router-dom";

function Signup() {
  const navigate = useNavigate();
  const [credentials, setCredentials] = React.useState({name: "", email: "", password: "",geolocation: ""});
  const handleSubmit = async(e) => {
    e.preventDefault();
    const response = await fetch('http://localhost:5000/api/createuser', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        name: credentials.name,
        email: credentials.email,
        password: credentials.password,
        location: credentials.geolocation
      }),
    });
      const json = await response.json();
      console.log(json);

      if (!json.success) {
  alert("Enter valid credentials");
} else {
  alert("Signup Successful!");
  navigate("/login");
}
    }
    const onChange = (event) => {
      setCredentials({...credentials, [event.target.name]: event.target.value})
    };
  
  return (
    <>
      <div className="container">
        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label htmlFor="name" className="form-label">
              Name
            </label>
            <input type="text" className="form-control" name="name" value={credentials.name} onChange={onChange} />
          </div>
          <div className="mb-3">
            <label htmlFor="exampleInputEmail1" className="form-label">
              Email address
            </label>
            <input
              type="email"
              className="form-control"
              id="exampleInputEmail1"
              aria-describedby="emailHelp"
              name="email" value={credentials.email} onChange={onChange}
            />
            <div id="emailHelp" className="form-text">
              We'll never share your email with anyone else.
            </div>
          </div>
          <div className="mb-3">
            <label htmlFor="exampleInputPassword1" className="form-label">
              Password
            </label>
            <input
              type="password"
              className="form-control"
              id="exampleInputPassword1"
              name="password" value={credentials.password} onChange={onChange}
            />
          </div>
          <div className="mb-3">
            <label htmlFor="exampleInputGeolocation" className="form-label">
              Geolocation
            </label>
            <input
              type="text"
              className="form-control"
              id="exampleInputGeolocation"
              name="geolocation" value={credentials.geolocation} onChange={onChange}
            />
          </div>

          <button type="submit" className="btn btn-success m-3">
            Submit
          </button>

          <Link to="/login" className="btn btn-danger m-3">
            Already have an account? Login here.
          </Link>
        </form>
      </div>
    </>
  );
}

export default Signup;
